column.value:
{
  "pageDescription": "Sample Creation & Full Metadata Capture",
  "validationNotes": {
    "firstNameMandatory": "First Name is the mandatory name field for individual order acceptance",
    "surnameOptional": "Surname/Last Name is NOT mandatory",
    "nationalIdOptional": "National ID is NOT required for order acceptance - it is optional"
  },
  "dataPoints": {
    "sampleIdentity": {
      "accessionNumber": {"type": "text", "label": "Pathology Accession Number (Lab Accession)", "generated": true, "required": true, "description": "Unique lab accession number"},
      "barcode": {"type": "barcode", "label": "Barcode/Label", "generated": true},
      "sampleCategory": {"type": "choice", "label": "Sample Category", "options": ["Clinical diagnostic", "Research"], "required": true}
    },
    "patientIdentification": {
      "firstName": {"type": "text", "label": "First Name", "required": true, "description": "MANDATORY - Primary name field for order acceptance"},
      "surname": {"type": "text", "label": "Surname/Last Name", "required": false, "description": "Optional - Not required for order acceptance"},
      "nationalId": {"type": "text", "label": "National ID", "required": false, "description": "OPTIONAL - Not required for order acceptance"}
    },
    "receivingInfo": {
      "receivedDateTime": {"type": "dateTime", "label": "Receiving Date & Time", "required": true, "description": "Date and time sample was received at the lab"},
      "receivedBy": {"type": "text", "label": "Receiving Staff Name", "required": true, "description": "Name of staff member who received the sample"},
      "sourceFacility": {"type": "choice", "label": "Source Facility", "options": ["Alert Hospital", "Research project", "External clinic", "Other"], "required": true}
    },
    "specimenInfo": {
      "specimenType": {
        "type": "reference",
        "label": "Specimen Type",
        "source": "type_of_sample",
        "categories": {
          "histopathology": ["FFPE tissue block", "Fresh biopsy", "Surgical resection"],
          "cytopathology": ["Fine needle aspirate (FNA)", "Pleural fluid", "Peritoneal fluid", "Pericardial fluid", "CSF for cytology", "Urine for cytology", "Sputum for cytology", "Cervical smear"],
          "hematology": ["EDTA blood (peripheral smear)"],
          "research": ["Human tissue (fresh)", "Human tissue (frozen)", "Human tissue (FFPE)", "Animal tissue (mouse footpad)", "Animal tissue (nerve)", "Bacterial/cellular pellet", "Primary cell culture"]
        },
        "required": true
      },
      "specimenSite": {"type": "text", "label": "Specimen Site/Location", "required": true, "placeholder": "e.g., liver biopsy, lung FNA, skin lesion", "description": "Anatomical site from which specimen was collected"},
      "collectionDateTime": {"type": "dateTime", "label": "Collection Date & Time", "required": true, "description": "Date and time specimen was collected from patient"}
    },
    "clinicalMetadata": {
      "patientId": {"type": "text", "label": "Patient ID", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": true, "description": "Hospital/clinic patient identifier"},
      "requestingClinician": {"type": "text", "label": "Requesting Clinician", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": true, "description": "Name of clinician who ordered the test"},
      "clinicalDetails": {"type": "textarea", "label": "Clinical Details/Indication", "conditionalOn": "sampleCategory == Clinical diagnostic", "required": true, "description": "Clinical history, indication for test, relevant findings"}
    },
    "researchMetadata": {
      "studyId": {"type": "text", "label": "Study ID", "conditionalOn": "sampleCategory == Research", "required": true, "description": "Research study/protocol identifier"},
      "piName": {"type": "text", "label": "Principal Investigator (PI) Name", "conditionalOn": "sampleCategory == Research", "required": true, "description": "Name of the principal investigator"},
      "participantAnimalId": {"type": "text", "label": "Participant ID / Animal ID", "conditionalOn": "sampleCategory == Research", "required": true, "description": "Research participant or animal identifier"},
      "ethicalApprovalRef": {"type": "text", "label": "Ethical Approval Reference", "conditionalOn": "sampleCategory == Research", "required": true, "description": "IRB/Ethics committee approval number"}
    }
  },
  "csvImportFields": [
    "firstName", "surname", "nationalId", "sampleCategory",
    "receivedDateTime", "receivedBy", "sourceFacility",
    "specimenType", "specimenSite", "collectionDateTime",
    "patientId", "requestingClinician", "clinicalDetails",
    "studyId", "piName", "participantAnimalId", "ethicalApprovalRef"
  ],
  "systemActions": ["Generate unique pathology accession number", "Generate label/barcode", "Set status: Created - Pending QC", "Print label"],
  "nextPage": "Sample Quality Control"
}
